// ============================================================
// Excel Import Type Definitions
// Generated by scripts/ingest-excel.ts
// All types represent the JSON shape written to data/excel-imports/
// ============================================================

// Shared metadata header on every output file
export type SheetMeta = {
  sheet_name: string;
  row_count: number;
  extracted_at: string; // ISO 8601
  warnings: string[];
};

// ──────────────────────────────────────────────
// Spell Vendors  →  spell-vendors.json
// ──────────────────────────────────────────────
export type SpellVendorRow = {
  _source_row: number;
  class: string;
  vendor_npc_name: string;
  location: string;
  floor_area: string;
  levels: string;
};

export type SpellVendorsOutput = SheetMeta & {
  records: SpellVendorRow[];
};

// ──────────────────────────────────────────────
// Tradeable Items & Schedule  →  tradeable-schedule.json
// ──────────────────────────────────────────────
export type TradeableScheduleRow = {
  _source_row: number;
  expansion: string;
  tradeable_items: string[];
  teek_schedule: string;
  unlock_date: string;
  epic_tradeables: string[];
};

export type TradeableScheduleOutput = SheetMeta & {
  records: TradeableScheduleRow[];
};

// ──────────────────────────────────────────────
// Epic 1.0 Quests  →  epic-quests.json
// ──────────────────────────────────────────────
export type EpicQuestStep = {
  _source_row: number;
  step: string | number;
  phase: string;
  action: string;
  npc_mob: string;
  zone: string;
  items: string;
  notes: string;
};

export type EpicQuestClass = {
  class_name: string;
  weapon_name: string;
  steps: EpicQuestStep[];
};

export type EpicQuestsOutput = SheetMeta & {
  classes: EpicQuestClass[];
};

