// ──────────────────────────────────────────────
// Normalization report  →  _normalization-report.json
// ──────────────────────────────────────────────
export type NormalizationMatch = {
  excel_name: string;
  source_sheet: string;
  source_row: number;
  status: "matched" | "not_found" | "partial";
  matched_name?: string;
  note?: string;
};

export type NormalizationReport = {
  generated_at: string;
  item_details_count: number;
  excel_items_checked: number;
  matched: number;
  not_found: number;
  partial: number;
  matches: NormalizationMatch[];
};
